sql:
SELECT DISTINCT user_id 
FROM tweets
WHERE tweet_id IN (
  SELECT tweet_id 
  FROM breed_predictions
);

SELECT AVG(total_likes) AS average_likes_per_user
FROM (
  SELECT user_id, SUM(num_likes) AS total_likes
  FROM tweets
  GROUP BY user_id
);

SELECT num_images
FROM tweets
WHERE tweet_id = 'abc123';

SELECT DISTINCT user_id 
FROM tweets 
WHERE year = 2022 AND month = 4;

external_knowledge:
- 'Influential users': Users with more than 1,000 followers;
- 'Within their own areas': Users' locations must match the locations where the tweets were posted;
- 'Engaging and highly-rated tweets': Tweets ranked by their rating and engagement levels, where engagement is the sum of comments, likes, and shares.

- 'active social media users' refers to users who have posted tweets;
- 'prolific' indicates the number of tweets posted by each user;
- 'typical quality of their posts' is measured by the average numerator rating given to their tweets.
